sql:
SELECT region_code
FROM household_statistics
WHERE source_id = 0;

SELECT year, region_code, growth_rate
FROM demographic_trends
WHERE growth_rate = (
    SELECT MAX(growth_rate) 
    FROM demographic_trends
);

SELECT total_households
FROM household_statistics
WHERE region_code = 'AG';

external_knowledge:
- 'lonely stars' refers to regions with predominantly single-person households (one_person_household > 30%);
- 'constellation-like families' metaphorically represent larger families, particularly those with five members (five_person_household < 10%);
- 'growth in household size minus the growth rate exceed 10% of their total households' means (average_household_size - growth_rate) > (total_households * 0.1).

sql:
SELECT average_size_household
FROM household_statistics
WHERE total_households > 30000;

SELECT r.region_name, hs.total_households
FROM household_statistics hs
INNER JOIN regions r ON hs.region_code = r.region_code;

SELECT type_name, AVG(median_income) AS average_median_income
FROM household_types
GROUP BY type_name;

SELECT region_name, country
FROM regions
ORDER BY region_name;

SELECT access_type 
FROM access_logs 
WHERE region_code = 'AG';

external_knowledge:
- "The land of AG" refers to the region with region_code 'AG';
- "Cradle of ages" is a metaphorical expression for the average median age of the population;
- "Total number of souls wandering" refers to the total population;
- "Typical family size" is the average size of households;
- "Wisdom of the people" refers to the average education level of the population.
